type ConversationStarterCardProps = {
  className?: string;
  icon?: ReactNode;
  initialCollaborationMode?: unknown;
  mode?: unknown;
  onSelect: (
    prompt: string,
    mode: unknown,
    initialCollaborationMode: unknown,
  ) => void;
  prompt: string;
};
type ConversationStarterIconProps = {
  className?: string;
  name: string;
};
function ConversationStarterCard({
  className,
  icon,
  mode,
  onSelect,
  initialCollaborationMode,
  prompt,
}: ConversationStarterCardProps) {
  const cardClassName = clsx(
    "group flex w-full flex-col items-start gap-2 rounded-4xl border border-token-border/50 bg-token-input-background/70 px-3 py-3 text-left text-base transition-colors hover:border-token-border hover:bg-token-input-background focus-visible:outline-token-border focus-visible:outline-2 focus-visible:outline-offset-2",
    className,
  );
  return (
    <button
      className={cardClassName}
      type="button"
      onClick={() => onSelect(prompt, mode, initialCollaborationMode)}
    >
      <span className="ml-1 inline-flex h-6 w-6 items-center justify-center">
        {icon}
      </span>
      <span className="w-full pl-1 text-left text-base text-token-text-primary">
        {renderPromptPreview(prompt)}
      </span>
    </button>
  );
}
function ConversationStarterIcon({
  className = "icon-md",
  name,
}: ConversationStarterIconProps) {
  const theme = useIsDark() ? "dark" : "light";
  const iconAssetName = name + "-" + theme + ".svg";
  const fallbackAssetName = "document-" + theme + ".svg";
  const iconSrc =
    ICON_ASSETS_BY_NAME[iconAssetName] ??
    ICON_ASSETS_BY_NAME[fallbackAssetName];
  return <img className={className} alt="" aria-hidden="true" src={iconSrc} />;
}
function renderPromptPreview(prompt: string): ReactNode {
  const firstSentence = getPromptFirstSentence(prompt);
  if (!firstSentence) return "";
  const parts: ReactNode[] = [];
  PROMPT_VARIABLE_PATTERN.lastIndex = 0;
  let cursor = 0;
  let match = PROMPT_VARIABLE_PATTERN.exec(firstSentence);
  while (match) {
    const matchIndex = match.index;
    if (matchIndex > cursor) {
      parts.push(firstSentence.slice(cursor, matchIndex));
    }
    parts.push(
      <span key={match[0] + "-" + matchIndex} className="font-medium">
        {match[0]}
      </span>,
    );
    cursor = matchIndex + match[0].length;
    match = PROMPT_VARIABLE_PATTERN.exec(firstSentence);
  }
  if (cursor < firstSentence.length) {
    parts.push(firstSentence.slice(cursor));
  }
  return parts;
}
function getPromptFirstSentence(prompt: string) {
  const trimmedPrompt = prompt.trim();
  if (trimmedPrompt.length === 0) return "";
  const firstNonEmptyLine = trimmedPrompt
    .split(/\r?\n/)
    .find((line) => line.trim().length > 0);
  if (!firstNonEmptyLine) return "";
  const trimmedLine = firstNonEmptyLine.trim();
  const firstSentenceMatch = trimmedLine.match(/^(.+?[.!?])(?:\s|$)/);
  return firstSentenceMatch ? firstSentenceMatch[1].trim() : trimmedLine;
}
export { ConversationStarterCard, ConversationStarterIcon };
